INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('f54857f73a11cb2e', 'MN', '["federal"]', 'candidate_eligibility', 'Is there a U.S. Senate race in Minnesota for the 2026 cycle?', '["Are Amy Klobuchar or Tina Smith up for re-election in 2026?","When is the next US Senate election in MN?","Is the Minnesota US Senate seat an open race?"]', 'Yes. There is an open U.S. Senate race in Minnesota in 2026. Incumbent Senator Tina Smith announced her retirement in February 2025 and is not seeking re-election. Senator Amy Klobuchar won re-election in 2024 and is not on the 2026 ballot.', 'https://www.sos.state.mn.us/election-administration-campaigns/elections-calendar/', 'Minnesota Secretary of State – Elections Calendar', '2026-05-12', 'volatile', 'official_source_direct', 'Federal candidates and consultants', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('371d81ac34778493', 'MN', '["state"]', 'candidate_eligibility', 'Is Governor Tim Walz running for re-election in 2026?', '["Is the Minnesota Governor''s seat open in 2026?","Can Walz seek a third term?","Minnesota 2026 gubernatorial race status"]', 'No. Governor Tim Walz announced in January 2026 that he will not seek a third term. Consequently, the 2026 Minnesota gubernatorial election is an open-seat race.', 'https://www.sos.state.mn.us/election-administration-campaigns/elections-calendar/', 'Minnesota Secretary of State – Elections Calendar', '2026-05-12', 'volatile', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('9efd86748f632d50', 'MN', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What does the ''DFL'' party label mean on a Minnesota ballot?', '["What is the Democratic party called in Minnesota?","DFL ballot designation MN","Is DFL the same as Democrat?"]', 'In Minnesota, the Democratic Party is officially named the Democratic-Farmer-Labor Party (DFL), the result of a 1944 merger. Democratic candidates legally appear on the ballot under the ''DFL'' designation rather than ''Democrat''.', 'https://www.revisor.mn.gov/statutes/cite/204B.07', 'Minn. Stat. § 204B.07', '2026-05-12', 'static', 'statute_citation', 'All candidates and campaigns', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('9ed46e655d042b07', 'MN', '["state"]', 'candidate_eligibility', 'Who are the prominent declared candidates for the open Minnesota Governor seat in 2026?', '["Is Amy Klobuchar running for Governor?","Who won the 2026 MN gubernatorial straw polls?","Frontrunners for MN Governor 2026"]', 'Following Tim Walz''s withdrawal, U.S. Senator Amy Klobuchar entered the gubernatorial race and won the DFL precinct caucus straw poll in February 2026 with roughly 72%. On the Republican side, State House Speaker Lisa Demuth won the GOP caucus straw poll with roughly 32%.', 'https://www.sos.state.mn.us/election-administration-campaigns/elections-calendar/', 'Minnesota Secretary of State – Candidate Filings', '2026-05-12', 'volatile', 'secondary_source', 'Campaign strategists and consultants', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('76418222638569eb', 'MN', '["state"]', 'candidate_eligibility', 'Who won the GOP and DFL caucus straw polls for Minnesota Governor in 2026?', '["2026 Minnesota caucus results","Demuth and Klobuchar straw poll","Minnesota Republican gubernatorial frontrunner"]', 'In the February 2026 precinct caucuses, Senator Amy Klobuchar won the DFL straw poll with approximately 72%, while State House Speaker Lisa Demuth won the Republican straw poll with approximately 32%.', 'https://www.sos.state.mn.us/election-administration-campaigns/elections-calendar/', 'Minnesota Secretary of State – Election Information', '2026-05-12', 'volatile', 'secondary_source', 'Campaign strategists', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('fe7f0ce9d7170459', 'MN', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Minnesota in 2026?', '["Who is on the state ballot in MN in 2026?","Is the Attorney General up for reelection?","Does Minnesota elect a State Treasurer?"]', 'The statewide executive offices on the 2026 ballot are Governor/Lieutenant Governor (open seat), Attorney General (Keith Ellison, incumbent), Secretary of State (Steve Simon, incumbent), and State Auditor (open seat, Julie Blaha retiring). Minnesota abolished the office of State Treasurer in 2003.', 'https://www.revisor.mn.gov/constitution/#article_5', 'Minnesota Constitution Article V', '2026-05-12', 'volatile', 'statute_citation', 'Statewide candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('1afb446e2f12506a', 'MN', '["state"]', 'redistricting', 'What is the partisan composition of the Minnesota House of Representatives for the 2026 cycle?', '["Who controls the state house in Minnesota?","Minnesota House tied 67-67","Power sharing agreement MN House 2026"]', 'Going into the 2026 elections, the Minnesota House of Representatives is exactly tied at 67-67 between the DFL and Republicans. This tie was restored after special elections in early 2025, operating under a power-sharing agreement with Republican Lisa Demuth as Speaker.', 'https://www.house.mn.gov/', 'Minnesota House of Representatives', '2026-05-12', 'volatile', 'official_source_direct', 'State Legislative candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('21edc6ede3c69445', 'MN', '["state"]', 'redistricting', 'What is the partisan composition of the Minnesota State Senate for the 2026 cycle?', '["Who controls the state senate in Minnesota?","Minnesota Senate majority 2026","Are all MN Senate seats up in 2026?"]', 'Going into the 2026 cycle, the DFL holds a minimum majority in the Minnesota State Senate. All 67 State Senate seats will be on the ballot in November 2026.', 'https://www.senate.mn/', 'Minnesota State Senate', '2026-05-12', 'volatile', 'official_source_direct', 'State Legislative candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('5d2af176b615e9ca', 'MN', '["state","judicial"]', 'finance_ethics', 'Who regulates state-level campaign finance in Minnesota?', '["Does the Secretary of State handle campaign finance in MN?","Jurisdiction of the CFB in Minnesota","Where do I file campaign finance reports for State Senate?"]', 'State-level campaign finance (Governor, statewide executives, state legislature, and judicial candidates) is administered and enforced by the Minnesota Campaign Finance and Public Disclosure Board (CFB), an agency wholly separate from the Secretary of State.', 'https://cfb.mn.gov/', 'Minnesota Campaign Finance and Public Disclosure Board', '2026-05-12', 'static', 'official_source_direct', 'State and Judicial candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('df2af3a9ceafbe48', 'MN', '["state","judicial"]', 'finance_ethics', 'What is the threshold for registering a candidate campaign committee with the Minnesota CFB?', '["When do I have to register a campaign committee in MN?","CFB registration dollar limit","How much can I spend before filing a committee?"]', 'A state-level candidate must register a principal campaign committee with the CFB within 14 days after receiving contributions or making disbursements of more than $750 in a calendar year.', 'https://www.revisor.mn.gov/statutes/cite/10A.105', 'Minn. Stat. § 10A.105', '2026-05-12', 'static', 'statute_citation', 'State and Judicial candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('89e2f57ca63b0f3d', 'MN', '["state"]', 'finance_ethics', 'What are the 2025-2026 contribution limits for a candidate running for Governor of Minnesota?', '["How much can an individual give to a Governor candidate in MN?","Statewide contribution limits Minnesota","Aggregate cycle limit for Governor"]', 'In Minnesota, limits apply per two-year election segment (not per election). For the 2025-2026 election segment, individuals and PACs may contribute up to an aggregate of $4,000 to a candidate for Governor/Lt. Governor.', 'https://cfb.mn.gov/pdf/publications/handbooks/Candidate_Handbook_State.pdf', 'Minn. Stat. § 10A.27(1)', '2026-05-12', 'per_cycle', 'statute_citation', 'Gubernatorial candidates and donors', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('793111ce5394eaf7', 'MN', '["state"]', 'finance_ethics', 'What are the 2025-2026 contribution limits for Attorney General, Secretary of State, and State Auditor in Minnesota?', '["Max donation for MN Attorney General 2026","State Auditor contribution limits","How much can I give to the Secretary of State?"]', 'During the 2025-2026 election segment, individuals and PACs may contribute up to $2,500 to a candidate for Attorney General, and up to $2,000 to a candidate for Secretary of State or State Auditor.', 'https://www.revisor.mn.gov/statutes/cite/10A.27', 'Minn. Stat. § 10A.27(1)', '2026-05-12', 'per_cycle', 'statute_citation', 'Statewide executive candidates and donors', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('2d46ebb1eb88acf6', 'MN', '["state"]', 'finance_ethics', 'What are the 2025-2026 contribution limits for State Senate and State House candidates in Minnesota?', '["Max donation for MN State Assembly 2026","MN State Senate contribution limits","Legislative cycle limits Minnesota"]', 'During the 2025-2026 election segment, individuals and PACs may contribute up to an aggregate of $1,000 to a candidate for the State Senate or the State House of Representatives. This covers the entire two-year segment.', 'https://www.revisor.mn.gov/statutes/cite/10A.27', 'Minn. Stat. § 10A.27(1)', '2026-05-12', 'per_cycle', 'statute_citation', 'State Legislative candidates and donors', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('2e569c3aed11eece', 'MN', '["state","county","municipal","judicial"]', 'finance_ethics', 'Can a corporation contribute directly to a candidate for office in Minnesota?', '["Are corporate contributions legal in MN?","Can my business donate to a state candidate?","Corporate direct prohibition Minnesota"]', 'No. Minnesota law strictly prohibits corporations (including for-profit and nonprofit corporations) and LLCs from using general treasury funds to make direct contributions to candidate campaigns or political party units.', 'https://www.revisor.mn.gov/statutes/cite/211B.15', 'Minn. Stat. § 211B.15', '2026-05-12', 'static', 'statute_citation', 'Corporations and Campaign Treasurers', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('1fe278807b2aeda8', 'MN', '["state","county","municipal","judicial"]', 'finance_ethics', 'Can labor unions contribute directly to a candidate from their general treasury in Minnesota?', '["Are union dues contributions legal in MN?","Labor union donation rules Minnesota","Do unions have to use a PAC?"]', 'Yes. Unlike corporations, labor unions are not included in the corporate prohibition under Minn. Stat. § 211B.15. Unions may use their general treasury funds to make direct contributions to state candidates, provided they register and report through a political fund with the Campaign Finance Board.', 'https://www.revisor.mn.gov/statutes/cite/211B.15', 'Minn. Stat. § 211B.15', '2026-05-12', 'static', 'statute_citation', 'Unions and Campaign Treasurers', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('32127c98428b98b7', 'MN', '["state"]', 'finance_ethics', 'What is the Public Subsidy Program for state candidates in Minnesota?', '["State matching funds MN","How does the public subsidy agreement work?","Do Minnesota candidates get public money?"]', 'The Public Subsidy Program provides direct state payments to state-level candidates who sign a Public Subsidy Agreement, obligating them to strict campaign spending limits. Spending limits can increase by 10% for first-time candidates or 20% in closely contested primaries.', 'https://www.revisor.mn.gov/statutes/cite/10A.31', 'Minn. Stat. § 10A.31', '2026-05-12', 'static', 'statute_citation', 'State-level candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('4f2ca494bef360f7', 'MN', '["state"]', 'finance_ethics', 'What is the Political Contribution Refund (PCR) Program in Minnesota?', '["Can donors get a refund from the state?","PCR maximum limit 2026","Minnesota $75 campaign donation refund"]', 'The PCR program allows individual donors to receive a direct cash refund from the state for contributions made to qualified Minnesota political parties and state candidates who have signed the Public Subsidy Agreement. For 2026, the maximum refund is $75 for an individual and $150 for a married couple filing jointly.', 'https://www.revisor.mn.gov/statutes/cite/290.06', 'Minn. Stat. § 290.06(23)', '2026-05-12', 'per_cycle', 'statute_citation', 'Donors and participating State Candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('8938aeaf84bc8f63', 'MN', '["state"]', 'finance_ethics', 'What is the sessional blackout rule for campaign contributions in Minnesota?', '["Lobbyist session ban MN","When are contributions banned for state reps?","Sessional blackout campaign finance"]', 'Under Minn. Stat. § 10A.273, candidates for the state legislature AND statewide constitutional offices are strictly prohibited from soliciting or accepting contributions from registered lobbyists, political committees, or political funds (PACs) during a regular legislative session. The blackout does not apply during special legislative sessions.', 'https://www.revisor.mn.gov/statutes/cite/10A.273', 'Minn. Stat. § 10A.273', '2026-05-12', 'static', 'statute_citation', 'State candidates, Lobbyists, and PACs', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('ac2cb2de379b7f51', 'MN', '["state"]', 'finance_ethics', 'What is the aggregate special source limit for Minnesota campaigns?', '["20% PAC limit rule Minnesota","How much can I take from lobbyists total?","Public Subsidy Program funding caps"]', 'Under Minn. Stat. § 10A.27(11), candidates who have signed a Public Subsidy Agreement cannot accept more than 20% of their total spending limit in combined aggregate contributions from lobbyists, political committees, and political funds. Exceeding this cap can result in a civil penalty up to four times the excess amount.', 'https://www.revisor.mn.gov/statutes/cite/10A.27', 'Minn. Stat. § 10A.27(11)', '2026-05-12', 'static', 'statute_citation', 'State candidates utilizing Public Subsidy', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('9a31f4af7ac96b09', 'MN', '["state","judicial"]', 'finance_ethics', 'What is the late contribution reporting rule for Minnesota state candidates?', '["24-hour reporting rule Minnesota","When do I have to report late donations?","20-day pre-election contribution reporting"]', 'If a candidate receives a contribution or loan of $1,000 or more (for statewide office) or $500 or more (for legislative/judicial office) during the 20 days immediately preceding a primary or general election, it must be reported to the CFB within 24 hours.', 'https://www.revisor.mn.gov/statutes/cite/10A.20', 'Minn. Stat. § 10A.20(5)', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('542171765fad6bc5', 'MN', '["state","judicial"]', 'finance_ethics', 'What is the itemized disclosure threshold for individual campaign contributions in Minnesota?', '["When do I have to list a donor''s name in MN?","Campaign contribution disclosure limit","Minnesota $200 donation rule"]', 'Campaign committees must itemize contributions from individuals that exceed $200 in aggregate during a calendar year. The disclosure filed with the CFB must include the contributor''s name, address, and employer or occupation.', 'https://www.revisor.mn.gov/statutes/cite/10A.20', 'Minn. Stat. § 10A.20(3)', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('de1af4b54c9208a6', 'MN', '["state","county","municipal","judicial"]', 'finance_ethics', 'What is the limit for anonymous campaign contributions in Minnesota?', '["Can I donate cash anonymously in MN?","Anonymous contribution cap Minnesota","Passing the hat rules campaign finance"]', 'Anonymous campaign contributions in Minnesota are strictly limited to $20 or less. Any anonymous contribution exceeding $20 must be forwarded to the Campaign Finance and Public Disclosure Board for deposit in the state''s general account.', 'https://www.revisor.mn.gov/statutes/cite/10A.15', 'Minn. Stat. § 10A.15(1)', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('7ba3c63771bb9951', 'MN', '["state","county","municipal"]', 'finance_ethics', 'Are foreign-influenced corporations banned from making campaign contributions in Minnesota?', '["Foreign contribution ban MN","Minnesota Chamber of Commerce v. Simon","Can multinational corporations donate in MN?"]', 'In 2023, Minnesota passed a law banning political contributions from foreign-influenced corporations. However, the Minnesota Chamber of Commerce sued, and a federal court issued a preliminary injunction staying the law. It is currently not operationally enforced pending litigation.', 'https://www.revisor.mn.gov/statutes/cite/211B.15', 'Minn. Stat. § 211B.15 (Enforcement Stayed)', '2026-05-12', 'volatile', 'statute_citation', 'Corporations and Campaign Treasurers', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('65170948331e0bfb', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Minnesota allow same-day voter registration at polling places?', '["Can I register to vote at the polls in Minnesota?","Same-day registration rules MN","Election day registration proof"]', 'Yes. Minnesota has allowed Election Day Registration since 1974 (the first state to do so). Eligible voters can register at their polling place on Election Day by providing authorized proof of residence, such as a valid Minnesota driver''s license with current address.', 'https://www.revisor.mn.gov/statutes/cite/201.061', 'Minn. Stat. § 201.061', '2026-05-12', 'static', 'statute_citation', 'Unregistered voters', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('523db32d006b897d', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Is a photo ID required to vote at the polls in Minnesota?', '["Minnesota voter ID laws","Do I need my driver''s license to vote in MN?","Poll ID requirements Minnesota"]', 'No. Under current law, Minnesota does not require voters to present a photo ID to cast a ballot at the polls, provided their voter registration is already current and active. Identity is verified via signature and identifying information against the poll roster.', 'https://www.sos.state.mn.us/elections-voting/election-day-voting/', 'Minnesota Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('1339aa7584053db4', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Did Minnesota voters pass a constitutional amendment requiring voter ID?', '["Question 5 voter ID failure Minnesota","Does the MN constitution require voter ID?","2012 voter ID ballot measure"]', 'No. In 2012, Minnesota voters rejected a legislatively referred constitutional amendment (Amendment 2) that would have required a valid photo ID to vote in person and established a system of provisional balloting. The measure failed, maintaining the state''s no-ID framework.', 'https://www.sos.state.mn.us/election-administration-campaigns/elections-calendar/', 'Minnesota Secretary of State – Election Results', '2026-05-12', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('aa3d5f693137da5e', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'How long is the early voting (absentee voting) window in Minnesota?', '["When does early voting start in MN?","46-day absentee voting rule","Minnesota in-person early voting duration"]', 'Minnesota offers a robust 46-day early voting window. Eligible voters may vote early via no-excuse absentee ballot, either by mail or in person at their local county election office, beginning 46 days prior to both the primary and general elections.', 'https://www.revisor.mn.gov/statutes/cite/203B.081', 'Minn. Stat. § 203B.081', '2026-05-12', 'static', 'statute_citation', 'All voters and Get-Out-The-Vote operations', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('b0bbf741ed28ee74', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Are secure drop boxes for absentee ballots legally mandated in Minnesota?', '["Can I put my absentee ballot in a drop box in MN?","Mail ballot drop boxes Minnesota","Does Minnesota require drop boxes for voting?"]', 'Drop boxes are permitted but not legally mandated statewide. Under recent state law, municipalities and counties may choose to establish secure absentee ballot drop boxes, provided they meet strict security, lighting, and retrieval standards outlined by the Secretary of State.', 'https://www.revisor.mn.gov/statutes/cite/203B.082', 'Minn. Stat. § 203B.082', '2026-05-12', 'static', 'statute_citation', 'Voters and Election Officials', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('f1945fd3341780f4', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the process for curing a rejected absentee ballot in Minnesota?', '["When do I have to fix my signature for my mail ballot?","Absentee ballot curing window MN","Minnesota mail ballot rejection notice"]', 'If an absentee ballot envelope is rejected more than five days before the election, the election official must mail a replacement ballot. If rejected within five days of the election, the official must attempt to contact the voter by telephone or email to provide instructions on how to cure the defect or vote in person.', 'https://www.revisor.mn.gov/statutes/cite/203B.121', 'Minn. Stat. § 203B.121', '2026-05-12', 'static', 'statute_citation', 'Absentee voters and Campaigns', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('b47237fa23b741ad', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'How does the voter registration vouching mechanism work in Minnesota?', '["Can someone vouch for my address to vote?","Election day registration without utility bill","Vouching for a voter MN"]', 'During Election Day Registration, if a voter lacks standard proof of residence, a registered voter from the same precinct can sign an oath ''vouching'' for the unregistered voter''s residence. A single registered voter can vouch for up to eight other voters in the precinct.', 'https://www.revisor.mn.gov/statutes/cite/201.061', 'Minn. Stat. § 201.061', '2026-05-12', 'static', 'statute_citation', 'Voters and Poll Watchers', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('ea54026b0a8ba395', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Can 16-year-olds pre-register to vote in Minnesota?', '["Teenager voter registration MN","Pre-registration age Minnesota","When can high school students register to vote?"]', 'Yes. 16- and 17-year-old citizens in Minnesota may submit a voter registration application. Their registration status remains ''pending'' until they turn 18, at which point they are automatically activated on the voter rolls.', 'https://www.revisor.mn.gov/statutes/cite/201.054', 'Minn. Stat. § 201.054', '2026-05-12', 'static', 'statute_citation', 'Unregistered voters and GOTV operations', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('b1ad54e532127c4a', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Can 17-year-olds vote in a partisan primary in Minnesota?', '["Voting in primary if 17 MN","Underage primary voting rules Minnesota","Do I have to be 18 to vote in the August primary?"]', 'Yes. Under a 2023 legislative change, a 17-year-old in Minnesota may vote in a primary election if they will turn 18 on or before the date of the subsequent general election.', 'https://www.revisor.mn.gov/statutes/cite/201.014', 'Minn. Stat. § 201.014', '2026-05-12', 'static', 'statute_citation', 'Young voters and Campaigns', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('6f9f48d052cec4a4', 'MN', '["federal","state","county","municipal","judicial"]', 'candidate_eligibility', 'Can a person with a felony conviction vote in Minnesota?', '["Felon voting rights MN","Voting post-incarceration rules Minnesota","2023 felony voting restoration law"]', 'Yes. Following the 2023 Restore the Vote Act, voting rights in Minnesota are automatically restored to individuals with felony convictions immediately upon their release from incarceration. Individuals do not lose their right to vote while on parole, probation, or supervised release.', 'https://www.revisor.mn.gov/statutes/cite/201.014', 'Minn. Stat. § 201.014', '2026-05-12', 'static', 'statute_citation', 'All eligible citizens', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('32efce74a017acd9', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Minnesota law require employers to give time off to vote?', '["Do I get paid time off to vote in MN?","Employee voting leave Minnesota","Any time of day to vote rule"]', 'Yes. Under a 2023 legislative change to Minn. Stat. § 204C.04, every eligible employee has the right to be absent from work for the time necessary to vote at any time during the day (or during early voting) without penalty or loss of pay, eliminating the previous ''morning only'' restriction.', 'https://www.revisor.mn.gov/statutes/cite/204C.04', 'Minn. Stat. § 204C.04', '2026-05-12', 'static', 'statute_citation', 'Voters and Employers', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('a8c6eb9001cac87b', 'MN', '["federal","state","county","municipal","judicial"]', 'election_dates', 'What are the standard polling place hours in Minnesota?', '["When do polls open and close in MN?","Minnesota election day voting hours","What time do polls close on Election Day?"]', 'The standard polling hours across Minnesota are from 7:00 a.m. to 8:00 p.m. Any voter who is in line at the polling place by 8:00 p.m. is legally permitted to cast their ballot.', 'https://www.revisor.mn.gov/statutes/cite/204C.05', 'Minn. Stat. § 204C.05', '2026-05-12', 'static', 'statute_citation', 'All voters', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('0ed91d54aaa978df', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the polling place electioneering buffer zone in Minnesota?', '["How close to the door can I campaign in MN?","100-foot rule Minnesota voting","Campaign signs at polling places"]', 'Minnesota enforces a 100-foot electioneering buffer zone measured from the building containing a polling place. During voting hours, no person may ask, solicit, or persuade a voter, nor distribute campaign materials within this boundary.', 'https://www.revisor.mn.gov/statutes/cite/211B.11', 'Minn. Stat. § 211B.11', '2026-05-12', 'static', 'statute_citation', 'Campaigns and Poll Workers', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('70178b9612fba9c1', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What are the criminal penalties for voter intimidation in Minnesota?', '["Is voter intimidation a felony in MN?","Election interference laws Minnesota","NRS 211B.075 intimidation rules"]', 'Under Minn. Stat. § 211B.075, using force, coercion, threats, or intimidation to compel a person to vote or refrain from voting, or to interfere with an election official, is a gross misdemeanor, elevated to a felony if the act involves a dangerous weapon or serious injury.', 'https://www.revisor.mn.gov/statutes/cite/211B.075', 'Minn. Stat. § 211B.075', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('5287e51d0152948e', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What are the rules for poll challengers versus observers in Minnesota?', '["Can I watch the vote counting in MN?","Poll watcher requirements Minnesota","Do election challengers need to be appointed?"]', 'In Minnesota, major political parties may appoint ''challengers'' in writing to be present at the polls. Challengers may only challenge a voter''s eligibility based on personal knowledge and are strictly prohibited from conversing directly with voters.', 'https://www.revisor.mn.gov/statutes/cite/204C.07', 'Minn. Stat. § 204C.07', '2026-05-12', 'static', 'statute_citation', 'Poll watchers and Campaigns', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('77730bdda7aa5a94', 'MN', '["federal","state","county","municipal","judicial"]', 'election_dates', 'When is the 2026 partisan primary election in Minnesota?', '["What date is the MN primary in 2026?","Minnesota August primary date","When do polls open for the MN partisan primary?"]', 'The Minnesota partisan primary election is scheduled for Tuesday, August 11, 2026.', 'https://www.revisor.mn.gov/statutes/cite/204D.03', 'Minn. Stat. § 204D.03', '2026-05-12', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('2699af51b1f1c8d6', 'MN', '["federal","state","county","municipal","judicial"]', 'election_dates', 'When is the 2026 general election in Minnesota?', '["What date is the MN general election in 2026?","Minnesota 2026 midterm election date","When is Election Day 2026 in Minnesota?"]', 'The general election in Minnesota will be held on Tuesday, November 3, 2026.', 'https://www.revisor.mn.gov/statutes/cite/204D.03', 'Minn. Stat. § 204D.03', '2026-05-12', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('2ff84b659ee4d523', 'MN', '["federal","state","county","municipal","judicial"]', 'filing_requirements', 'What is the candidate filing window for the 2026 elections in Minnesota?', '["When is the deadline to file for office in MN?","Minnesota candidate filing period 2026","How long is the filing window in Minnesota?"]', 'For the 2026 election cycle, the official candidate filing period opens on Tuesday, May 19, 2026, and closes at 5:00 p.m. on Tuesday, June 2, 2026, for federal, state, and county offices.', 'https://www.revisor.mn.gov/statutes/cite/204B.09', 'Minn. Stat. § 204B.09', '2026-05-12', 'per_cycle', 'statute_citation', 'All candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('fc637fd78a124993', 'MN', '["federal","state","county","municipal","judicial"]', 'filing_requirements', 'What are the candidate filing fees in Minnesota?', '["How much does it cost to run for office in MN?","Minnesota filing fee schedule 2026","Does Minnesota charge a filing fee for candidates?"]', 'Minnesota charges filing fees: $400 for U.S. Senator; $300 for U.S. Representative, Governor, statewide executive offices, and judicial offices; and $100 for State Senator or State Representative.', 'https://www.revisor.mn.gov/statutes/cite/204B.11', 'Minn. Stat. § 204B.11', '2026-05-12', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('4f79bf6a6187163c', 'MN', '["federal","state","county","municipal","judicial"]', 'filing_requirements', 'Can a candidate bypass the filing fee in Minnesota?', '["Petition in place of filing fee MN","How to waive the ballot fee in Minnesota","Signature alternative for candidates"]', 'Yes. A candidate may submit a Petition in Place of Filing Fee. For statewide offices, the petition requires 2,000 signatures. For U.S. House, it requires 1,000 signatures. For State Legislature, it requires 500 signatures.', 'https://www.revisor.mn.gov/statutes/cite/204B.11', 'Minn. Stat. § 204B.11(2)', '2026-05-12', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('ff4d181f245c88f2', 'MN', '["federal","state","county","municipal","judicial"]', 'filing_requirements', 'What is an Affidavit of Candidacy in Minnesota?', '["How do I declare my candidacy in MN?","Minnesota candidate paperwork","Affidavit of candidacy requirement"]', 'The Affidavit of Candidacy is the formal, notarized document a candidate must file during the designated filing period to have their name placed on the ballot. It affirms the candidate''s eligibility and intent to serve if elected.', 'https://www.revisor.mn.gov/statutes/cite/204B.06', 'Minn. Stat. § 204B.06', '2026-05-12', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('cbc5e774846b76fc', 'MN', '["state","judicial"]', 'filing_requirements', 'When must a candidate file a Statement of Economic Interest in Minnesota?', '["Financial disclosure form deadline MN","CFB economic interest filing","How many days do I have to disclose my assets?"]', 'Candidates for state-level offices must file a Statement of Economic Interest with the Campaign Finance and Public Disclosure Board (CFB) within 14 days after officially filing their Affidavit of Candidacy.', 'https://www.revisor.mn.gov/statutes/cite/10A.09', 'Minn. Stat. § 10A.09', '2026-05-12', 'static', 'statute_citation', 'State and Judicial candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('2bfca00d54ebad55', 'MN', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for Governor in Minnesota?', '["How old do you have to be to be MN Governor?","Gubernatorial candidate residency rules","Lieutenant Governor candidate qualifications"]', 'Under the Minnesota Constitution, a candidate for Governor or Lieutenant Governor must be a qualified voter, at least 25 years of age at the time of the election, and have resided in Minnesota for at least one year prior to the election.', 'https://www.revisor.mn.gov/constitution/#article_5', 'Minnesota Constitution Article V § 2', '2026-05-12', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('a4762a6539561bfa', 'MN', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for the Minnesota State Legislature?', '["How old to run for State Senate MN?","Residency rules State Representative Minnesota","Do I have to live in the district to run for House?"]', 'A candidate for the Minnesota State Senate or State House of Representatives must be a qualified voter, at least 21 years of age, a resident of Minnesota for one year, and a resident of the legislative district for six months immediately preceding the general election.', 'https://www.revisor.mn.gov/constitution/#article_4', 'Minnesota Constitution Article IV § 6', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('2561537d6ea5ee32', 'MN', '["federal"]', 'candidate_eligibility', 'What are the age and residency requirements to run for U.S. House in Minnesota?', '["Do I have to live in the district to run for Congress in MN?","Congressional age limit Minnesota","US House qualifications"]', 'Under the U.S. Constitution, a candidate for the U.S. House of Representatives must be at least 25 years old, a U.S. citizen for seven years, and an inhabitant of Minnesota when elected. District residency is not required.', 'https://www.sos.state.mn.us/election-administration-campaigns/become-a-candidate/candidate-qualifications/', 'Minnesota Secretary of State / U.S. Constitution Art. I § 2', '2026-05-12', 'static', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('b65435fdeaab63ba', 'MN', '["judicial"]', 'candidate_eligibility', 'What are the qualifications to run for the Minnesota Supreme Court or Court of Appeals?', '["Do Supreme Court justices have to be lawyers in MN?","Minnesota judicial qualifications","Learned in the law requirement"]', 'A candidate for the Minnesota Supreme Court, Court of Appeals, or District Court must be ''learned in the law,'' meaning they must be licensed to practice law as an attorney in Minnesota.', 'https://www.revisor.mn.gov/constitution/#article_6', 'Minnesota Constitution Article VI § 5', '2026-05-12', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('7d5e826b03c17b49', 'MN', '["judicial"]', 'election_dates', 'How are judges selected for the Minnesota Supreme Court and Court of Appeals?', '["Are Supreme Court judges elected in MN?","Minnesota judicial elections contested","Are there retention elections for judges in Minnesota?"]', 'Minnesota judges are selected in nonpartisan, contested elections for six-year terms. Unlike some states that use yes/no retention elections, Minnesota judges face potential challengers on the ballot, though incumbents are rarely challenged.', 'https://www.revisor.mn.gov/constitution/#article_6', 'Minnesota Constitution Article VI § 7', '2026-05-12', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('7e10ab7351d4c9b2', 'MN', '["federal"]', 'election_dates', 'How are vacancies in the U.S. Senate filled in Minnesota?', '["Who replaces a US Senator from Minnesota?","Does the Governor appoint Senate vacancies in MN?","Special election for US Senate"]', 'If a U.S. Senate seat becomes vacant, the Governor appoints a temporary replacement to serve until a special election is held. The special election occurs at the next November state general election, provided the vacancy occurs at least 11 weeks before the regular primary.', 'https://www.revisor.mn.gov/statutes/cite/204D.28', 'Minn. Stat. § 204D.28', '2026-05-12', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('76c6db985c5504a0', 'MN', '["federal"]', 'election_dates', 'How are vacancies in the U.S. House of Representatives filled in Minnesota?', '["Does the Governor appoint US House vacancies?","Special election for Congress MN","Congressional vacancy fill Minnesota"]', 'Vacancies in the U.S. House of Representatives are filled exclusively by a special election called by the Governor. The Governor does not have the authority to appoint an interim U.S. Representative.', 'https://www.revisor.mn.gov/statutes/cite/204D.17', 'Minn. Stat. § 204D.17', '2026-05-12', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('0d8ec3d8e0a0df27', 'MN', '["state"]', 'election_dates', 'Who succeeds the Governor of Minnesota in the event of a vacancy?', '["What happens if the MN Governor resigns?","Lieutenant Governor succession Minnesota","Gubernatorial vacancy fill"]', 'If the Governor dies, resigns, or is removed, the Lieutenant Governor becomes the Governor for the remainder of the unexpired term.', 'https://www.revisor.mn.gov/constitution/#article_5', 'Minnesota Constitution Article V § 5', '2026-05-12', 'static', 'statute_citation', 'Statewide officials', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('0d4eaaaa4bd3c21e', 'MN', '["state"]', 'election_dates', 'How are interim vacancies filled for the Minnesota Secretary of State, Attorney General, or State Auditor?', '["Who replaces the Minnesota Auditor if they resign?","Statewide office vacancy fill procedure","Does the Governor appoint the Attorney General?"]', 'If a vacancy occurs in the office of Secretary of State, Attorney General, or State Auditor, the Governor appoints an interim replacement who serves out the remainder of the unexpired term until the next scheduled general election.', 'https://www.revisor.mn.gov/statutes/cite/351.06', 'Minn. Stat. § 351.06', '2026-05-12', 'static', 'statute_citation', 'Statewide executive officials', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('8e69460f0e4c3db5', 'MN', '["state"]', 'election_dates', 'How are vacancies in the Minnesota State Legislature filled?', '["Special election for State Assembly MN","Does the Governor appoint state senators?","Legislative vacancy fill Minnesota"]', 'Under Minn. Stat. § 204D.19, legislative vacancies are filled exclusively by a special election called by the Governor. Minnesota has no interim appointment mechanism for the legislature. A primary is held before the special election. If the vacancy occurs near the very end of a term with no regular or special session scheduled, the seat may remain unfilled until the general election.', 'https://www.revisor.mn.gov/statutes/cite/204D.19', 'Minn. Stat. § 204D.19', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('5302ad658003f28c', 'MN', '["judicial"]', 'election_dates', 'How are mid-term vacancies filled in the Minnesota court system?', '["Who appoints judges in Minnesota?","Commission on Judicial Selection","Judicial vacancy fill process MN"]', 'When a mid-term vacancy occurs in the Supreme Court, Court of Appeals, or District Court, the Commission on Judicial Selection evaluates candidates and recommends nominees to the Governor, who then makes the appointment.', 'https://www.revisor.mn.gov/statutes/cite/480B.01', 'Minn. Stat. § 480B.01', '2026-05-12', 'static', 'statute_citation', 'Judicial candidates and Legal Counsel', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('ceb16c6468601732', 'MN', '["federal","state"]', 'redistricting', 'Who drew the state legislative and congressional maps currently used in Minnesota?', '["Minnesota Special Redistricting Panel","Who draws the maps in Minnesota?","Wattson v Simon 2022 maps"]', 'Following a legislative deadlock, the current 2022-2030 redistricting maps were drawn by the Minnesota Special Redistricting Panel, a five-judge panel appointed by the Chief Justice of the Minnesota Supreme Court in the case Wattson v. Simon.', 'https://www.gis.lcc.mn.gov/html/redistricting.html', 'Minnesota Legislature – Redistricting', '2026-05-12', 'static', 'official_source_direct', 'All federal and state candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('f3e543af9293b8f8', 'MN', '["federal"]', 'redistricting', 'How many congressional districts does Minnesota have for the 2026 cycle?', '["Number of US House seats in MN","Minnesota congressional apportionment","How many electoral votes does Minnesota have?"]', 'Based on the post-2020 census apportionment, Minnesota retained its 8 U.S. House districts, granting the state a total of 10 Electoral College votes.', 'https://www.sos.state.mn.us/election-administration-campaigns/elections-calendar/', 'Minnesota Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('f6f7ef0ecec799a8', 'MN', '["state"]', 'redistricting', 'How do State Senate and State House districts overlap in Minnesota?', '["Nesting requirement Minnesota redistricting","How many house seats are in a senate district?","MN legislative district structure"]', 'Minnesota utilizes a strict ''nesting'' requirement in its redistricting process. Each of the 67 State Senate districts is divided exactly in half to create two State House districts (e.g., Senate District 1 contains House Districts 1A and 1B), totaling 134 House districts.', 'https://www.gis.lcc.mn.gov/html/redistricting.html', 'Minnesota Legislature – Redistricting', '2026-05-12', 'static', 'official_source_direct', 'State Legislative candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('83cc6e48688d9064', 'MN', '["state","judicial"]', 'recall_rules', 'Can voters recall a statewide official or state legislator in Minnesota?', '["Statewide recall mechanism MN","How to recall the Governor in Minnesota","Recall grounds malfeasance Minnesota"]', 'Yes, but the mechanism is strictly limited. Under Article VIII of the Minnesota Constitution, state executive officers, legislators, and judges may be recalled, but ONLY on specific grounds of serious malfeasance or nonfeasance in the performance of their duties, or conviction of a serious crime.', 'https://www.revisor.mn.gov/constitution/#article_8', 'Minnesota Constitution Article VIII § 6', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('e20474928e2ff87c', 'MN', '["state"]', 'election_dates', 'What is the structure of the Minnesota Legislature''s session?', '["Does the Minnesota legislature meet every year?","Biennial legislative session MN","120-day session limit Minnesota"]', 'The Minnesota Legislature meets annually, but operates within a biennium (e.g., 2025-2026). Typically, the odd year features a long budget session, and the even year features a shorter policy session. Constitutionally, the legislature cannot meet for more than 120 legislative days within the biennium.', 'https://www.revisor.mn.gov/constitution/#article_4', 'Minnesota Constitution Article IV § 12', '2026-05-12', 'static', 'statute_citation', 'State Legislators and Consultants', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('7f4b9bd38f2c2546', 'MN', '["state"]', 'election_dates', 'Who can call a special session of the Minnesota Legislature?', '["Special session authority MN","Can the legislature convene itself?","Governor proclamation for special session"]', 'Only the Governor of Minnesota has the constitutional authority to call the Legislature into a special session by proclamation. Unlike some states, the Minnesota Legislature cannot unilaterally convene itself into a special session.', 'https://www.revisor.mn.gov/constitution/#article_4', 'Minnesota Constitution Article IV § 12', '2026-05-12', 'static', 'statute_citation', 'State Legislators', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('b069047438df3da6', 'MN', '["state"]', 'ballot_access', 'How can the Minnesota Legislature place a constitutional amendment on the ballot?', '["Legislative referral for constitutional amendment MN","How does the legislature change the MN constitution?","Constitutional amendment passage margin"]', 'The Minnesota Legislature can place a constitutional amendment on the ballot by passing a bill with a simple majority vote in both chambers. To become law, the amendment must then be ratified by a majority of ALL voters casting a ballot at the next general election (not just a majority of those voting on the specific question).', 'https://www.revisor.mn.gov/constitution/#article_9', 'Minnesota Constitution Article IX § 1', '2026-05-12', 'static', 'statute_citation', 'State Legislators and Campaigns', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('76a9a146af6aa513', 'MN', '["state"]', 'ballot_access', 'Does Minnesota have a statewide citizen initiative or referendum process?', '["Can citizens put a law on the ballot in MN?","Minnesota ballot initiative rules","Referendum process Minnesota"]', 'No. Minnesota does not have a statewide initiative or referendum process. Citizens cannot collect signatures to place a statute or constitutional amendment directly on the statewide ballot.', 'https://www.sos.state.mn.us/election-administration-campaigns/elections-calendar/', 'Minnesota Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('783a0b490352a47c', 'MN', '["state"]', 'ballot_access', 'What is the single-subject rule for legislation in Minnesota?', '["Can an omnibus bill cover multiple topics in MN?","Single-subject requirement Minnesota","Minnesota Constitution Article 4 restrictions"]', 'The Minnesota Constitution mandates that no law shall embrace more than one subject, which shall be expressed in its title. This prevents the attachment of unrelated ''riders'' to legislation.', 'https://www.revisor.mn.gov/constitution/#article_4', 'Minnesota Constitution Article IV § 17', '2026-05-12', 'static', 'statute_citation', 'State Legislators and Legal Counsel', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('1fb158ef4d25f715', 'MN', '["county","municipal","special_district"]', 'election_dates', 'How many counties does Minnesota have, and who administers elections locally?', '["How many counties in MN?","County auditor role in Minnesota elections","Who runs local elections in MN?"]', 'Minnesota has 87 counties. Election administration is handled at the county level by the County Auditor, often in coordination with municipal (city or town) clerks.', 'https://www.sos.state.mn.us/election-administration-campaigns/elections-calendar/', 'Minnesota Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'Candidates and Local Officials', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('cd9ccc9c5cab8ec8', 'MN', '["county"]', 'election_dates', 'Are County Sheriff elections partisan in Minnesota?', '["Is the sheriff race partisan in MN?","Sheriff nonpartisan election Minnesota","County executive officer terms"]', 'No. In Minnesota, the office of County Sheriff is a nonpartisan position. Candidates run for four-year terms without a political party label on the ballot.', 'https://www.revisor.mn.gov/statutes/cite/382.01', 'Minn. Stat. § 382.01', '2026-05-12', 'static', 'statute_citation', 'County-level candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('e78d0dd8ee0f2a59', 'MN', '["municipal"]', 'runoff_rules', 'Do any cities in Minnesota use Ranked-Choice Voting (RCV)?', '["Is ranked choice voting used for Mayor in Minneapolis?","RCV rules St. Paul","Municipal ranked-choice voting MN"]', 'Yes. While RCV is not used statewide, several major municipalities, including Minneapolis and St. Paul, utilize Ranked-Choice Voting for their mayoral, city council, and other municipal elections.', 'https://www.sos.state.mn.us/elections-voting/how-elections-work/ranked-choice-voting/', 'Minnesota Secretary of State – Ranked-Choice Voting', '2026-05-12', 'static', 'official_source_direct', 'Municipal Candidates in specific cities', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('b5168f4e850730cf', 'MN', '["special_district","municipal"]', 'election_dates', 'Are local school board and township elections partisan in Minnesota?', '["School board trustee elections MN","Do school board candidates run with a party label?","Township election structure"]', 'Local school board and township elections in Minnesota are strictly nonpartisan. Candidates do not run with a political party affiliation.', 'https://www.sos.state.mn.us/election-administration-campaigns/elections-calendar/', 'Minnesota Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'Local candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('4fa26553964cd5ba', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the SVRS in Minnesota?', '["Statewide voter registration system MN","How are voter rolls managed in MN?","Secretary of State SVRS database"]', 'The Statewide Voter Registration System (SVRS) is the centralized, top-down voter registration database managed by the Minnesota Secretary of State. It networks with all 87 counties to manage voter rolls, absentee balloting, and Election Day Registration.', 'https://www.sos.state.mn.us/election-administration-campaigns/elections-calendar/', 'Minnesota Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'Election Officials and Consultants', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('0fad062cb0c994a6', 'MN', '["federal","state"]', 'runoff_rules', 'What triggers an automatic recount for statewide or federal offices in Minnesota?', '["Automatic recount margin Minnesota","When is a recount required by law in MN?","0.25% recount rule"]', 'An automatic, state-funded recount is triggered for a federal, statewide, or judicial office if the margin of victory between the winning and losing candidate is less than one-quarter of one percent (0.25%) of the total votes cast for that office.', 'https://www.revisor.mn.gov/statutes/cite/204C.35', 'Minn. Stat. § 204C.35(1)(a)', '2026-05-12', 'static', 'statute_citation', 'Federal and Statewide candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('022dc85be4cd3525', 'MN', '["state"]', 'runoff_rules', 'What triggers an automatic recount for state legislative offices in Minnesota?', '["State Senate automatic recount margin","State House recount threshold MN","0.5% recount rule legislative"]', 'An automatic, state-funded recount is triggered for a State Senate or State House office if the margin of victory between the winning and losing candidate is less than one-half of one percent (0.5%) of the total votes cast for that office.', 'https://www.revisor.mn.gov/statutes/cite/204C.35', 'Minn. Stat. § 204C.35(1)(b)', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('50d9b88bee236f28', 'MN', '["federal","state","county","municipal","judicial"]', 'runoff_rules', 'How are election contests adjudicated in Minnesota?', '["Contesting an election result MN","Who hears election fraud disputes?","Minn. Stat. Chapter 209"]', 'Any eligible voter or defeated candidate may contest an election over irregularities, illegal votes, or errors in canvassing. Under Minn. Stat. Chapter 209, a formal notice of contest is filed in district court, which holds a trial without a jury to adjudicate the dispute.', 'https://www.revisor.mn.gov/statutes/cite/209', 'Minn. Stat. Chapter 209', '2026-05-12', 'static', 'statute_citation', 'Candidates and Legal Counsel', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('4b90a1f5dbfabcde', 'MN', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Minnesota use provisional ballots?', '["Provisional ballot rules Minnesota","Voting if my name isn''t on the roster MN","How to cast a provisional ballot"]', 'Because Minnesota utilizes widespread Election Day Registration (SDR) and a robust vouching mechanism, it does not use traditional provisional ballots to resolve voter eligibility at the polls. Eligible voters simply register on the spot to cast a regular ballot.', 'https://www.sos.state.mn.us/elections-voting/election-day-voting/', 'Minnesota Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'Voters and poll watchers', 'batch_2026-05-13T02-52-24_minnesota_full_v1'),
  ('eb66e32722ca833f', 'MN', '["state","county","municipal","judicial"]', 'finance_ethics', 'What are the rules for disposing of surplus campaign funds in Minnesota?', '["Surplus funds disposition MN","Can I give my leftover campaign money to charity?","What happens to campaign money when I close my committee?"]', 'Surplus campaign funds cannot be converted to personal use. Upon terminating a committee, remaining funds may be returned to contributors pro-rata, transferred to a political party unit, or donated to the state general fund. Limits exist on transfers to other candidates.', 'https://www.revisor.mn.gov/statutes/cite/10A.241', 'Minn. Stat. § 10A.241', '2026-05-12', 'static', 'statute_citation', 'Candidates concluding campaigns', 'batch_2026-05-13T02-52-24_minnesota_full_v1')
